// Keywords that signal breaking or high-impact GHL changes
const KEYWORDS = [
  'breaking', 'deprecated', 'removed',
  'api', 'webhook', 'oauth', 'scope',
  'migration', 'sunset', 'v2',
  'workflow', 'custom field', 'pipeline'
];

// Get static data to track last checked date
const staticData = this.getWorkflowStaticData('global');
const lastCheckedDate = staticData.lastCheckedDate || '1970-01-01T00:00:00Z';
const lastCheckedTime = new Date(lastCheckedDate).getTime();

const rawData = $input.first().json;
let xmlText = '';

// Handle different response formats
if (typeof rawData === 'string') {
  xmlText = rawData;
} else if (rawData.data && typeof rawData.data === 'string') {
  xmlText = rawData.data;
} else if (rawData.body && typeof rawData.body === 'string') {
  xmlText = rawData.body;
} else {
  xmlText = JSON.stringify(rawData);
}

// Parse RSS/XML items using regex (n8n Code node has no DOMParser)
const items = [];
const itemRegex = /<item>(.*?)<\/item>/gs;
let match;
while ((match = itemRegex.exec(xmlText)) !== null) {
  const itemXml = match[1];
  const getTag = (tag) => {
    const r = new RegExp(`<${tag}><!\\[CDATA\\[(.+?)\\]\\]><\\/${tag}>|<${tag}>(.+?)<\\/${tag}>`, 's');
    const m = itemXml.match(r);
    return m ? (m[1] || m[2] || '').trim() : '';
  };
  items.push({
    title: getTag('title'),
    link: getTag('link'),
    pubDate: getTag('pubDate'),
    description: getTag('description')
  });
}

const matched = [];
let newestDate = lastCheckedDate;

for (const item of items) {
  const itemDate = item.pubDate ? new Date(item.pubDate) : null;
  if (!itemDate || isNaN(itemDate.getTime())) continue;
  if (itemDate.getTime() <= lastCheckedTime) continue;

  if (itemDate.toISOString() > newestDate) {
    newestDate = itemDate.toISOString();
  }

  // Strip HTML tags for keyword matching
  const plainDesc = (item.description || '').replace(/<[^>]*>/g, ' ').toLowerCase();
  const plainTitle = (item.title || '').toLowerCase();
  const text = plainTitle + ' ' + plainDesc;

  const hits = KEYWORDS.filter(kw => text.includes(kw.toLowerCase()));
  if (hits.length > 0) {
    matched.push({
      title: item.title,
      keywords: hits,
      url: item.link,
      published: item.pubDate
    });
  }
}

staticData.lastCheckedDate = newestDate;
staticData.lastRunAt = new Date().toISOString();

return [{ json: { matchedCount: matched.length, updates: matched, lastChecked: lastCheckedDate, newLastChecked: newestDate } }];

const data = $input.first().json;
const updates = data.updates;

const facts = updates.map(u => ({
  type: 'FactSet',
  facts: [
    { title: 'Update', value: u.title },
    { title: 'Keywords', value: u.keywords.join(', ') },
    { title: 'Published', value: u.published ? new Date(u.published).toLocaleDateString() : 'N/A' }
  ]
}));

const actions = updates.slice(0, 5).map(u => ({
  type: 'Action.OpenUrl',
  title: `View: ${u.title.substring(0, 40)}`,
  url: u.url
}));

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    contentUrl: null,
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          size: 'Medium',
          weight: 'Bolder',
          text: `GHL Breaking Changes Alert (${updates.length} update${updates.length > 1 ? 's' : ''})`
        },
        {
          type: 'TextBlock',
          text: `Checked updates since ${new Date(data.lastChecked).toLocaleDateString()}`,
          isSubtle: true,
          wrap: true
        },
        ...facts
      ],
      actions: actions
    }
  }]
};

return [{ json: { teamsPayload: card } }];
